export const GlobalEndpointsResponseDataSource = {
  live: 'live',
  mock: 'mock',
  none: 'none',
} as const;

export interface GlobalEndpointRow {
  id: string;
  appId: string;
  appName: string;
  name: string;
  region: string;
  status: Status;
  latencyMs: number;
  packetLossPercent: number;
}

export interface GlobalEndpointsResponse {
  endpoints: GlobalEndpointRow[];
  /** Whether Azure is configured and live endpoint data is being served. */
  liveEnabled: boolean;
  /** 'live' = Azure Resource Graph query succeeded, 'mock' = Azure configured but query returned no resources, 'none' = Azure not configured. */
  dataSource: GlobalEndpointsResponseDataSource;
  /** Timestamp of when endpoint data was last fetched from Azure Resource Graph. Only present when dataSource is live. */
  dataAsOf?: string;
}

export interface GlobalCostByAppItem {
  appId: string;
  appName: string;
  environment: string;
  /** Month-to-date spend in USD */
  monthToDate: number;
  /** Week-over-week percentage change (e.g. '+8.2%' or '-3.1%'). Null when insufficient data. */
  trend?: string | null;
}

