export interface BudgetAlertLogEntry {
  id: number;
  appId: string;
  appName: string;
  /** Month-to-date spend at alert time */
  mtd: number;
  /** End-of-month cost forecast at alert time */
  forecast: number;
  /** Budget cap at alert time */
  budget: number;
  /** Notification channels that fired (e.g. "teams", "email") */
  channels: string[];
  /** When the notification was dispatched */
  sentAt: string;
  /** When the entry was acknowledged by an operator. Null if not yet acknowledged. */
  acknowledgedAt?: string | null;
  /** Optional freetext note left by the operator when acknowledging. */
  acknowledgedNote?: string | null;
}

export interface AcknowledgeBudgetAlertBody {
  /**
     * Optional freetext note (e.g. "spike from load test, safe to ignore")
     * @maxLength 500
     */
  note?: string;
}

/**
 * Which notification channels are currently configured (env vars present). No secrets are exposed.
 */
export interface AlertChannelStatus {
  /** True when ALERT_TEAMS_WEBHOOK_URL (global or per-app) is set */
  teams: boolean;
  /** True when ALERT_SMTP_HOST + ALERT_SMTP_FROM + ALERT_EMAIL_TO are all set */
  email: boolean;
}

/**
 * Per-app infra alert threshold overrides. Pass null for a field to clear the DB override and revert to env-var / global default.
 */
export interface UpdateAlertConfigBody {
  /**
     * CPU alert threshold (percent). Null clears the DB override.
     * @minimum 1
     * @maximum 100
     */
  cpuThresholdPct?: number | null;
  /**
     * Memory alert threshold (percent). Null clears the DB override.
     * @minimum 1
     * @maximum 100
     */
  memoryThresholdPct?: number | null;
  /**
     * Consecutive over-threshold checks required before a notification fires. Null clears the DB override.
     * @minimum 1
     */
  consecutiveChecks?: number | null;
}

/**
 * Which source provides the effective CPU threshold
 */
export type AppAlertConfigCpuSource = typeof AppAlertConfigCpuSource[keyof typeof AppAlertConfigCpuSource];


export const AppAlertConfigCpuSource = {
  db: 'db',
  env: 'env',
  default: 'default',
} as const;

/**
 * Which source provides the effective memory threshold
 */
export type AppAlertConfigMemorySource = typeof AppAlertConfigMemorySource[keyof typeof AppAlertConfigMemorySource];


export const AppAlertConfigMemorySource = {
  db: 'db',
  env: 'env',
  default: 'default',
} as const;

/**
 * Which source provides the effective consecutive-checks value
 */
export type AppAlertConfigConsecutiveChecksSource = typeof AppAlertConfigConsecutiveChecksSource[keyof typeof AppAlertConfigConsecutiveChecksSource];


export const AppAlertConfigConsecutiveChecksSource = {
  db: 'db',
  env: 'env',
  default: 'default',
} as const;

/**
 * Which source provides the effective cooldown (env = ALERT_COOLDOWN_HOURS[__APPID], default = 12h built-in)
 */
export type AppAlertConfigCooldownSource = typeof AppAlertConfigCooldownSource[keyof typeof AppAlertConfigCooldownSource];


export const AppAlertConfigCooldownSource = {
  env: 'env',
  default: 'default',
} as const;

export interface AppAlertConfig {
  appId: string;
  appName: string;
  /** Effective CPU alert threshold (percent) */
  cpuThresholdPct: number;
  /** Effective memory alert threshold (percent) */
  memoryThresholdPct: number;
  /** True when a per-app DB or env-var value overrides the global default */
  cpuIsOverride: boolean;
  /** True when a per-app DB or env-var value overrides the global default */
  memoryIsOverride: boolean;
  /** Number of consecutive over-threshold scheduler checks required before a notification fires */
  consecutiveChecks: number;
  /** True when a per-app DB or env-var value overrides the global default */
  consecutiveChecksIsOverride: boolean;
  /** Effective alert cooldown window in hours (minimum time between repeat notifications) */
  cooldownHours: number;
  /** True when a per-app ALERT_COOLDOWN_HOURS__<APPID> env var overrides the global default */
  cooldownIsOverride: boolean;
  /** Which source provides the effective CPU threshold */
  cpuSource?: AppAlertConfigCpuSource;
  /** Which source provides the effective memory threshold */
  memorySource?: AppAlertConfigMemorySource;
  /** Which source provides the effective consecutive-checks value */
  consecutiveChecksSource?: AppAlertConfigConsecutiveChecksSource;
  /** Which source provides the effective cooldown (env = ALERT_COOLDOWN_HOURS[__APPID], default = 12h built-in) */
  cooldownSource?: AppAlertConfigCooldownSource;
  /** When a DB override was last saved for this app */
  updatedAt?: string | null;
  /** Display name / UPN of the operator who last saved DB overrides */
  updatedBy?: string | null;
}

export interface AppThresholds {
  appId: string;
  /** CPU utilisation % at which the SLO badge turns warning/critical. */
  cpuThreshold: number;
  /** Memory utilisation % at which the SLO badge turns warning/critical. */
  memoryThreshold: number;
  /** UPN of the operator who last changed the thresholds, or 'system' when still at defaults (no DB override). */
  updatedBy: string;
  /** When the thresholds were last changed by an operator. Absent when still at defaults (no DB override). */
  updatedAt?: string;
}

export interface UpdateAppThresholdsBody {
  /**
     * @minimum 1
     * @maximum 100
     */
  cpuThreshold: number;
  /**
     * @minimum 1
     * @maximum 100
     */
  memoryThreshold: number;
}

export interface AppThresholdsLogEntry {
  id: number;
  appId: string;
  /** CPU threshold before this change (null for the first-ever set) */
  oldCpuThreshold?: number | null;
  /** CPU threshold set by this change */
  newCpuThreshold: number;
  /** Memory threshold before this change (null for the first-ever set) */
  oldMemoryThreshold?: number | null;
  /** Memory threshold set by this change */
  newMemoryThreshold: number;
  /** UPN / identifier of the operator who made the change */
  changedBy: string;
  /** When the change was recorded */
  changedAt: string;
}

export interface AlertThresholdConfigLogEntry {
  id: number;
  appId: string;
  /** CPU threshold before this change (null = no prior DB override) */
  oldCpuThresholdPct?: number | null;
  /** CPU threshold set by this change (null = override was cleared) */
  newCpuThresholdPct?: number | null;
  /** Memory threshold before this change (null = no prior DB override) */
  oldMemoryThresholdPct?: number | null;
  /** Memory threshold set by this change (null = override was cleared) */
  newMemoryThresholdPct?: number | null;
  /** Consecutive-checks before this change (null = no prior DB override) */
  oldConsecutiveChecks?: number | null;
  /** Consecutive-checks set by this change (null = override was cleared) */
  newConsecutiveChecks?: number | null;
  /** Display name / UPN of the operator who made the change */
  changedBy: string;
  /** When the change was recorded */
  changedAt: string;
}

export interface AppThresholdsLogPage {
  items: AppThresholdsLogEntry[];
  /** Total number of history entries for this app (used for pagination) */
  total: number;
}

export interface InfraAlertLogEntry {
  id: number;
  appId: string;
  appName: string;
  /** Which metric breached — 'cpu' or 'memory' */
  metric: string;
  /** Observed metric value (percent) at alert time */
  value: number;
  /** Configured threshold (percent) that was exceeded */
  threshold: number;
  /** Notification channels that fired (e.g. "teams", "email") */
  channels: string[];
  /** When the notification was dispatched */
  sentAt: string;
  /** When the entry was acknowledged by an operator. Null if not yet acknowledged. */
  acknowledgedAt?: string | null;
}

